#include <stdio.h>
#include <sys/ipc.h>
#include <sys/shm.h>
#include <string.h>

#define SHM_SIZE 1024

int main() {
 // Generate unique key
 key_t key = ftok("/tmp", 'A');
 if (key == -1) {
 perror("ftok");
 return 1;
 }

 // Create shared memory segment
 int shmid = shmget(key, SHM_SIZE, IPC_CREAT | 0666);
 if (shmid == -1) {
 perror("shmget");
 return 1;
 }

 // Attach to shared memory
 char *shm_ptr = (char *)shmat(shmid, NULL, 0);
 if (shm_ptr == (char *)-1) {
 perror("shmat");
 return 1;
 }

 // Write data to shared memory
 char message[] = "Hello from Producer!";
 strcpy(shm_ptr, message);

 printf("Producer: Written to shared memory\n");

 // Wait for consumer to read (in real scenario, use semaphores)
 sleep(2);

 // Detach from shared memory
 if (shmdt(shm_ptr) == -1) {
 perror("shmdt");
 return 1;
 }

 // Optionally remove shared memory
 // shmctl(shmid, IPC_RMID, NULL);

 return 0;
}

#include <stdio.h>
#include <sys/ipc.h>
#include <sys/shm.h>

#define SHM_SIZE 1024

int main() {
 // Same key as producer
 key_t key = ftok("/tmp", 'A');
 if (key == -1) {
 perror("ftok");
 return 1;
 }

 // Get existing shared memory (don't create)
 int shmid = shmget(key, SHM_SIZE, 0666);
 if (shmid == -1) {
 perror("shmget");
 return 1;
 }

 // Attach to shared memory
 char *shm_ptr = (char *)shmat(shmid, NULL, SHM_RDONLY);
 if (shm_ptr == (char *)-1) {
 perror("shmat");
 return 1;
 }

 // Read data from shared memory
 printf("Consumer: Read from shared memory: %s\n", shm_ptr);

 // Detach from shared memory
 if (shmdt(shm_ptr) == -1) {
 perror("shmdt");
 return 1;
 }

 return 0;
}

#include <stdio.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>

#define SHM_NAME "/my_shared_mem"
#define SHM_SIZE 256

int main() {
 // Create and open shared memory object
 int fd = shm_open(SHM_NAME, O_CREAT | O_RDWR, 0666);
 if (fd == -1) {
 perror("shm_open");
 return 1;
 }

 // Set the size of the shared memory object
 if (ftruncate(fd, SHM_SIZE) == -1) {
 perror("ftruncate");
 return 1;
 }

 // Map the shared memory object
 void *ptr = mmap(NULL, SHM_SIZE, PROT_READ | PROT_WRITE, 
 MAP_SHARED, fd, 0);
 if (ptr == MAP_FAILED) {
 perror("mmap");
 return 1;
 }

 // Write to shared memory
 strcpy((char *)ptr, "Hello from POSIX shared memory!");
 printf("Written to POSIX shared memory\n");

 // Unmap
 if (munmap(ptr, SHM_SIZE) == -1) {
 perror("munmap");
 return 1;
 }

 // Close and unlink
 close(fd);
 shm_unlink(SHM_NAME);

 return 0;
}

#include <stdio.h>
#include <sys/ipc.h>
#include <sys/shm.h>
#include <sys/sem.h>
#include <string.h>

union semun {
 int val;
 struct semid_ds *buf;
 unsigned short *array;
};

// Semaphore operations
void sem_lock(int semid) {
 struct sembuf sb = {0, -1, 0}; // Decrement (wait)
 if (semop(semid, &sb, 1) == -1) {
 perror("semop lock");
 }
}

void sem_unlock(int semid) {
 struct sembuf sb = {0, 1, 0}; // Increment (signal)
 if (semop(semid, &sb, 1) == -1) {
 perror("semop unlock");
 }
}

int main() {
 key_t key = ftok("/tmp", 'B');

 // Create shared memory
 int shmid = shmget(key, 256, IPC_CREAT | 0666);
 char *shm = (char *)shmat(shmid, NULL, 0);

 // Create semaphore (binary - for mutual exclusion)
 int semid = semget(key, 1, IPC_CREAT | 0666);
 union semun arg;
 arg.val = 1; // Initial value = 1 (unlocked)
 semctl(semid, 0, SETVAL, arg);

 // Producer: write with lock
 sem_lock(semid);
 strcpy(shm, "Protected message");
 printf("Producer: Wrote to shared memory\n");
 sem_unlock(semid);

 // Consumer: read with lock
 sem_lock(semid);
 printf("Consumer: Read: %s\n", shm);
 sem_unlock(semid);

 // Cleanup
 shmdt(shm);
 shmctl(shmid, IPC_RMID, NULL);
 semctl(semid, 0, IPC_RMID);

 return 0;
}

#include <stdio.h>
#include <sys/mman.h>
#include <unistd.h>
#include <string.h>
#include <sys/wait.h>

#define SHM_SIZE 256

int main() {
 // Create anonymous shared memory
 void *shared_mem = mmap(NULL, SHM_SIZE, 
 PROT_READ | PROT_WRITE,
 MAP_SHARED | MAP_ANONYMOUS, 
 -1, 0);

 if (shared_mem == MAP_FAILED) {
 perror("mmap");
 return 1;
 }

 // Fork child process
 pid_t pid = fork();

 if (pid == 0) {
 // Child process - write to shared memory
 strcpy((char *)shared_mem, "Message from child");
 printf("Child: Wrote to shared memory\n");
 return 0;
 } else {
 // Parent process - wait for child
 wait(NULL);
 // Read from shared memory
 printf("Parent: Read: %s\n", (char *)shared_mem);
 }

 // Cleanup
 munmap(shared_mem, SHM_SIZE);

 return 0;
}
